import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"4/ Agentic engineering hiring: give candidates a real project, deploy it, then break it — @stephzhan","description":"","frontmatter":{"title":"4/ Agentic engineering hiring: give candidates a real project, deploy it, then break it — @stephzhan","author":"Stephanie Zhan（@stephzhan）","date":"2026-04-29T00:00:00.000Z","source":"https://x.com/stephzhan/status/2049518668909105313","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-29-@stephzhan-105313.md","filePath":"research/tweets/2026-04-29-@stephzhan-105313.md","lastUpdated":1779894392000}'),i={name:"research/tweets/2026-04-29-@stephzhan-105313.md"};function h(s,t,o,d,l,p){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="_4-agentic-engineering-hiring-give-candidates-a-real-project-deploy-it-then-break-it-—-stephzhan" tabindex="-1">4/ Agentic engineering hiring: give candidates a real project, deploy it, then break it — @stephzhan <a class="header-anchor" href="#_4-agentic-engineering-hiring-give-candidates-a-real-project-deploy-it-then-break-it-—-stephzhan" aria-label="Permalink to &quot;4/ Agentic engineering hiring: give candidates a real project, deploy it, then break it — @stephzhan&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/stephzhan/status/2049518668909105313" target="_blank" rel="noreferrer">https://x.com/stephzhan/status/2049518668909105313</a><strong>作者</strong>：Stephanie Zhan（@stephzhan） <strong>發布日期</strong>：2026-04-29 <strong>收錄日期</strong>：2026-05-01 <strong>類型</strong>：推文 <strong>統計</strong>：32 likes · 2 retweets · 14 bookmarks · 2901 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>4/ Hiring has not caught up.</p><p>If you want to hire agentic engineers, toy puzzles are the wrong test.</p><p>Give candidates a real project. Let them use the tools. Make them deploy it. Then try to break it with agents.</p><p>The question is no longer just: can you solve the problem?</p><p>It&#39;s: can you ship a system that survives contact with reality?</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Agentic engineer 的面試標準應是「能否 ship 一個能在現實中存活的系統」，而非傳統 LeetCode 題。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>傳統 toy puzzle 面試（LeetCode/算法題）無法評估 agentic engineering 能力</li><li>正確評估方法：給真實專案 → 讓用工具 → 部署 → 用 agent 破壞測試</li><li>評估核心問題從「能解決問題嗎？」→「能 ship 一個能生存的系統嗎？」</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>測試流程：real project → use tools → deploy → break it with agents（4 步驟）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>「用 agent 破壞測試」是有創意的評估框架；對應 cc-workspace 的 healthcheck.sh + deep-review 就是對 agent 輸出的「破壞測試」</li><li>實際面試中執行難度高：需要時間、環境、評估標準，hiring 成本會顯著上升</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>5/10</td><td>評估框架對 cc-workspace 設計有參考，但非直接整合點</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>「用 agent 破壞測試」作為面試環節是新穎的</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>觀點性建議，無面試效果數據</td></tr><tr><td>D. 技術深度 (15%)</td><td>4/10</td><td>概念層面</td></tr><tr><td>E. 泛化性 (15%)</td><td>6/10</td><td>特定情境（hiring），非所有 agent 工程師適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.0/10</strong></td><td>5×0.3+6×0.2+4×0.2+4×0.15+6×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：總分 5.0，hiring 框架對個人 workspace 無直接整合價值</p>',22)])])}const u=e(i,[["render",h]]);export{c as __pageData,u as default};
